function mergeSuperioreData() {
  if (typeof DATA === 'undefined' || typeof SUPERIORE_DATA === 'undefined') return;

  SUPERIORE_DATA.forEach(function(supCountry) {
    var existing = DATA.find(function(c) { return c.id === supCountry.id; });
    if (existing) {
      supCountry.regions.forEach(function(supRegion) {
        var existingRegion = existing.regions.find(function(r) { return r.id === supRegion.id; });
        if (existingRegion) {
          supRegion.wineries.forEach(function(supWinery) {
            var existingWinery = existingRegion.wineries.find(function(w) {
              return w.id === supWinery.id || w.name.toLowerCase() === supWinery.name.toLowerCase();
            });
            if (existingWinery) {
              // Enrich existing winery wines with superiore data
              var existingNames = existingWinery.wines.map(function(w) { return w.name.toLowerCase(); });
              supWinery.wines.forEach(function(wine) {
                var idx = existingWinery.wines.findIndex(function(w) {
                  return w.name.toLowerCase() === wine.name.toLowerCase();
                });
                if (idx >= 0) {
                  // Enrich existing wine entry
                  var ew = existingWinery.wines[idx];
                  if (!ew.grape || ew.grape === 'Unknown') ew.grape = wine.grape;
                  if (!ew.description || ew.description.length < 40) ew.description = wine.description;
                  if (!ew.score || ew.score < wine.score) ew.score = wine.score;
                  ew.superioreAvailable = true;
                  ew.superiorePrice = wine.superiorePrice;
                  ew.superioreUrl   = wine.superioreUrl;
                } else if (existingNames.indexOf(wine.name.toLowerCase()) === -1) {
                  existingWinery.wines.push(wine);
                  existingNames.push(wine.name.toLowerCase());
                }
              });
            } else {
              existingRegion.wineries.push(supWinery);
            }
          });
        } else {
          existing.regions.push(supRegion);
        }
      });
    } else {
      DATA.push(supCountry);
    }
  });

  DATA.sort(function(a, b) { return a.name.localeCompare(b.name); });
}
